import { Button } from "@/components/ui/button";
import Link from "next/link";

export function NavBar(props: React.ComponentProps<"nav">) {
    return (
      // Navigation
      <nav className="relative z-10 flex justify-end items-center p-6" {...props}>
        <div className="flex gap-4">
          <Button
            variant="ghost"
            className="text-white hover:bg-white/20 text-sm font-medium"
          >
            List a Space
          </Button>

          <Button
            asChild
            className="bg-white/90 text-gray-900 hover:bg-white text-sm font-medium px-6"
          >
            <Link href="/register">Sign in</Link>
          </Button>
        </div>
      </nav>
    );
}